INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('</b>,,[],[Mới hôm nào', 'cây gấc còn nhỏ xíu', 'xoè ra vài chiếc lá xanh non xinh xắn.', 'Vậy mà chỉ hơn một tháng sau', 'ngọn gấc đã bỏ khắp giàn', 'xanh mơn mởn.', 'Rồi sau đó', 'cây gấc bắt đầu trổ những bông hoa đầu tiên.', 'Hoa gấc to bản', 'xoè ra năm cánh dày dặn.', 'Thêm những bông hoa gấc', 'mái nhà xanh trước sân như được tô điểm thêm bằng hàng trăm ngọn đèn màu trắng ngà xinh xắn.],,,,,,,', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('q-manual-1771238140994', 'quiz-1771225368087', 'IMAGE_QUESTION', 'Câu văn nào sử dụng biện pháp so sánh và nhân hóa mô tả đúng hình ảnh dưới đây?', 'Trong vườn, những quả sầu riêng bắt đầu chín, hương thơm ngạt ngào lan xa trong không gian.|Những quả sầu riêng bụ bẫm, tinh nghịch đung đưa trên cành như những con nhím lớn, mình chi chít gai nhọn.|Những người nông dân đi thu hoạch sầu riêng chín, đem ra chợ bán.|Những múi sầu riêng chín vàng, vị ngọt ngào như mật ong và béo ngậy như bơ sữa.', 'B', '', '', '', '[]', '', '', '', 'https://liveazotastoragept112025.azota.vn/exam_questions/m02_2026/d15/105478111/bbf060809e5349b7a12ad79c443bb0f8.png');
