INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('q-manual-1771242590463', 'quiz-1771225368087', 'IMAGE_QUESTION', 'Câu văn nào sử dụng biện pháp so sánh mô tả đúng hình ảnh dưới đây?', 'Nhìn từ trên cao xuống, những thửa ruộng xanh biếc như những bậc thang bắc lên trời.|Trên những ruộng lúa xanh biếc, mấy cô bác nông dân chăm chỉ đi làm cỏ, bón phân.|Ruộng bậc thang là nét đặc trưng của thiên nhiên vùng Tây Bắc.|Cánh đồng lúa như một thâm vàng trải rộng đến tận chân trời.', 'A', '', '', '', '[]', '', '', '', 'https://res.cloudinary.com/dwv7hot9x/image/upload/v1771228159/CAU_5_stwap6.png');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('q-manual-1771242787730', 'quiz-1771225368087', 'IMAGE_QUESTION', 'Sắp xếp các tiếng sau thành câu văn hoàn chỉnh.', 'Chúng em tham dự kết nạp lễ Đội.|Chúng em tham dự lễ kết nạp Đội.|Chúng em tham dự Đội lễ kết nạp.|Chúng em kết nạp Đội tham dự.', 'B', '', '', '', '[]', '', '', '', 'https://liveazotastoragept112025.azota.vn/exam_questions/m02_2026/d15/105478111/0cfe150e749e3c2aa51bce243adea087.png');
