INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('</b>Đọc xong câu chuyện “Đồng hồ Mặt Trời”', 'em vô cùng yêu thích cậu bé I-sắc Niu-tơn.', '', '', '', '', '', '', '', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Trong câu chuyện', 'I-sắc Niu-tơn là một cậu bé ham học hỏi. Dù còn nhỏ tuổi nhưng Niu-tơn đã có thể tự tay làm ra các món đồ chơi cầu kì. Đặc biệt', 'Niu-tơn còn có tài quan sát vô cùng tỉ mỉ', 'cẩn thận. Cậu đã ghi chép lại sự thay đổi về vị trí của chiếc bóng. Từ đó', 'chế tạo ra đồng hồ mặt trời. Đây là một sáng chế vô cùng hữu ích với bà con trong làng. Nhờ có chiếc đồng hồ mà mọi người có thể nhận biết được thời gian. Qua nhân vật', 'em học được sự kiên trì', 'sẵn sàng tích lũy kiến thức mọi lúc', 'mọi nơi.', '', '', '', '', '', '');
