INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Rằm Trung thu năm nay', 'Ly thích nhất là có ông bà nội đến chơi. Bố trải hai cái chiếu to nhất ra giữa sân. Bà bổ bưởi. Mẹ gọt hồng. Còn Ly thì chăm chỉ', 'lụi cụi đi lấy rổ', 'lấy đĩa cho mẹ.', '', '', '', '', '', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Khi cả nhà bắt đầu phá cỗ thì con mèo trắng nhảy tót từ trong bếp ra. Con mèo này nghịch lắm', 'hôm nọ nó làm Ly bị mắng oan. Nó tha cuộn chỉ của mẹ vào gầm giường để chơi', 'thế mà mẹ cứ bảo Ly làm mất. Nhưng thôi', 'hôm nay cũng phải chia phần cho nó', 'kẻo tội. Ly gắp mấy miếng bưởi vào đĩa nhỏ cho mèo. Nó không biết ăn bưởi', 'cũng chả biết ăn hồng', 'chán thế! Ly đang băn khoăn chưa biết cho mèo ăn gì thì ông nội chỉ về phía giữa rằm bụt', 'nhắc: “Mọi người xem', 'trăng đã lên kìa!”.', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Ly ngẩng nhìn trăng. Còn bé Đốm thì cứ với tay về phía trăng mà reo lên như vớ được thứ gì đó: “Của Đốm! Của Đốm!”. Chỉ thương cho mèo chẳng biết trông trăng. Nó cứ chạy quanh sân lung tung', 'chốc chốc lại nhảy về cái bóng của mây qua cửa sổ. Ly bỗng nghĩ ra một cách. Ly lặng lẽ vào bếp lấy cái đĩa nhôm mẹ vẫn dùng cho mèo ăn cơm', 'múc nước đổ đầy đĩa', 'rồi bưng ra sân đặt trước mặt mèo. Xem kìa', 'mèo đã thấy trăng rồi! Nó nhìn chăm chăm vào lòng đĩa', 'tai giương giương', 'đuôi ngoáy ra điều thú vị lắm.', '', '', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Ly ghé khuôn mặt rạng rỡ cùng trăng trăng với mèo. Trăng trong đĩa nước bé hơn trăng trên trời nhưng sáng long lanh như viên ngọc. Con mèo ngước nhìn Ly', 'kêu “meo meo” cảm ơn', 'rồi thò chân vào đĩa định quẫy trăng. Ui thật!', '', '', '', '', '', '', '', '', '', '', '');
