INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES (',Vì trong đĩa có vẽ hình mặt trăng.|Vì hình ảnh của mặt trăng phản chiếu vào nước trong đĩa.|Vì đĩa có hình tròn nên mèo tưởng đó là mặt trăng.|Vì chiếc đĩa có màu vàng nên mèo tưởng đó là mặt trăng.,B,,,,,,,,', '', '', '', '', '', '', '', '', '', '', '', '', '');
