INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('q-manual-1772213767430', 'quiz-1772207252556', 'DRAG_DROP', 'Em hãy chọn chủ ngữ thích hợp điền vào chỗ trống để hoàn thành đoạn văn sau.', '', '', '', 'Chiều hôm ấy, trời mưa như trút nước. [Bầu trời]đầy mây đen và chớp giật loé từng đợt.', '', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('[Na] đã học bài xong và đang ngồi nhìn ra cửa sổ. [Cô bé] nhìn thấy một đoạn đường vắng lặng', 'trắng xoá màn mưa. Dưới lòng đường', '[người và xe] di chuyển hối hả. [Cả dãy phố] hầu như không có một mái hiên nào đưa ra mặt đường. Một chút lo âu dâng lên trong tâm trí. Na chạy xuống nhà bảo mẹ kéo mái hiên ra phía ngoài đường để người đi đường có chỗ trú mưa…', '', '', '', '', '', '', '', '', '', '', '');
