INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Sinh thời', 'ông có công rất lớn trong việc tìm ra cách phòng và chữa bệnh lao phổi. Dù ở đâu', 'bất cứ lúc nào người bệnh cần', 'ông đều có mặt để thăm khám và chữa trị kịp thời. Không ít lần', 'ông đã tự tiếp máu của mình cho người bệnh. Hình ảnh quen thuộc', 'thân thương của ông trong chiếc áo choàng trắng với ống nghe', 'ân cần thăm hỏi từng bệnh nhân', 'túc trực bên giường những người bệnh nặng…còn mãi trong tâm trí đồng nghiệp.', '', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('Mọi người gọi ông là “Bác sĩ của nhân dân”. Nhiều bệnh viện', 'trường học và các công trình trên mọi miền đất nước được vinh dự mang tên ông. Từ năm 2009', 'tên của bác sĩ Phạm Ngọc Thạch được đặt cho giải thưởng nhằm vinh danh những y', 'bác sĩ trẻ tích cực học tập', 'không ngừng rèn luyện và cống hiến cho ngành Y tế nước nhà.', '', '', '', '', '', '', '', '', '');
INSERT OR REPLACE INTO questions (id, quiz_id, type, question, options, correct_answer, items, text_field, blanks, distractors, sentence, words, correct_word_indexes, image) VALUES ('<i>Bài đọc trên cho ta thấy bác sĩ Phạm Ngọc Thạch là người như thế nào?</i>,Một bác sĩ yêu nghề.|Một bác sĩ giỏi.|Một người bác sĩ có trái tim nhân ái.|Tất cả các đáp án trên đều đúng.,D,,,,,,,,', '', '', '', '', '', '', '', '', '', '', '', '', '');
