INSERT OR REPLACE INTO results (student_name, class_name, quiz_id, quiz_title, score, correct_count, total_questions, submitted_at, answers) VALUES ('Lò Thị Thanh Tâm', '4A9', 'quiz-1770205530380', 'Ôn tập: Quy đồng mẫu số các phân số', 0, 1, 20, '2026-02-11T14:09:18.013Z', '{"q-1770211296984-0":{"isCorrect":false,"questionSnapshot":{"question":"Mục đích chính của việc quy đồng mẫu số hai phân số là gì?","mainQuestion":"","type":"MCQ","options":["A. Để làm cho tử số bằng nhau","B. Để đưa hai phân số về cùng một mẫu số","C. Để làm cho phân số nhỏ đi","D. Để biến đổi phân số thành số tự nhiên"],"correctAnswer":"B"}},"q-1770211296984-1":{"isCorrect":false,"questionSnapshot":{"question":"Mẫu số chung nhỏ nhất của hai phân số $\\frac{1}{3}$ và $\\frac{1}{6}$ là bao nhiêu?","mainQuestion":"","type":"MCQ","options":["A. 3","B. 6","C. 9","D. 18"],"correctAnswer":"B"}},"q-1770211296984-2":{"isCorrect":false,"questionSnapshot":{"question":"Tìm mẫu số chung nhỏ nhất của hai phân số $\\frac{2}{5}$ và $\\frac{3}{10}$.","mainQuestion":"","type":"SHORT_ANSWER","correctAnswer":"10"}},"q-1770211296984-3":{"isCorrect":false,"questionSnapshot":{"question":"","mainQuestion":"Đánh giá các phát biểu sau về việc chọn mẫu số chung (MSC):","type":"TRUE_FALSE","items":[{"statement":"MSC phải là số chia hết cho mẫu số của cả hai phân số."},{"statement":"MSC bắt buộc phải là tích của hai mẫu số."}]}},"q-1770211296984-4":{"selectedAnswer":"B","isCorrect":false,"questionSnapshot":{"question":"Khi quy đồng mẫu số hai phân số $\\frac{5}{9}$ và $\\frac{4}{3}$, ta nên chọn mẫu số chung là số nào để đơn giản nhất?","mainQuestion":"","type":"MCQ","options":["A. 27","B. 12","C. 9","D. 3"],"correctAnswer":"C"}},"q-1770211296984-6":{"isCorrect":false,"questionSnapshot":{"question":"Để quy đồng mẫu số phân số $\\frac{3}{4}$ thành phân số có mẫu số là 12, ta cần nhân cả tử và mẫu của phân số đó với số nào?","mainQuestion":"","type":"MCQ","options":["A. 2","B. 3","C. 4","D. 5"],"correctAnswer":"B"}},"q-1770211296984-7":{"isCorrect":false,"questionSnapshot":{"question":"Điền số thích hợp vào chỗ chấm: $\\frac{2}{5}$ = \\frac{...}{15}$","mainQuestion":"","type":"SHORT_ANSWER","correctAnswer":"6"}},"q-1770211296984-8":{"isCorrect":false,"questionSnapshot":{"question":"Những số nào sau đây có thể dùng làm mẫu số chung cho hai phân số $\\frac{1}{2}$ và $\\frac{1}{5}$? (Chọn tất cả đáp án đúng)(MSC chia hết cho cả 2 và 5)","mainQuestion":"","type":"MULTIPLE_SELECT","options":["A. 10","B. 15","C. 20","D. 7"],"correctAnswer":"[\"A\",\"C\"]"}},"q-1770211296984-9":{"selectedAnswer":"B","isCorrect":true,"questionSnapshot":{"question":"Phân số nào dưới đây đã được quy đồng từ phân số $\\frac{1}{2}$ với mẫu số chung là 8?","mainQuestion":"","type":"MCQ","options":["A. $\\frac{2}{8}$","B. $\\frac{4}{8}$","C. $\\frac{1}{8}$","D. $\\frac{6}{8}$"],"correctAnswer":"B"}},"q-1770211296984-10":{"isCorrect":false,"questionSnapshot":{"question":"Quy đồng mẫu số hai phân số $\\frac{1}{2}$ và $\\frac{3}{4}$, ta được hai phân số nào?","mainQuestion":"","type":"MCQ","options":["A. $\\frac{2}{4}$ và $\\frac{3}{4}$","B. $\\frac{1}{4}$ và $\\frac{3}{4}$","C. $\\frac{4}{4}$ và $\\frac{3}{4}$","D. $\\frac{3}{4}$ và $\\frac{3}{4}$"],"correctAnswer":"A"}},"q-1770211296984-11":{"isCorrect":false,"questionSnapshot":{"question":"Quy đồng mẫu số các phân số $\\frac{1}{2}$ và $\\frac{3}{10}$ với mẫu số chung là 10. Kết quả là:","mainQuestion":"","type":"MCQ","options":["A. $\\frac{5}{10}$ và $\\frac{3}{10}$","B. $\\frac{1}{10}$ và $\\frac{6}{10}$","C. $\\frac{5}{10}$ và $\\frac{6}{10}$","D. $\\frac{2}{10}$ và $\\frac{5}{10}$"],"correctAnswer":"A"}},"q-1770211296984-12":{"selectedAnswer":{"1":"5/8","3":"8/8"},"isCorrect":false,"questionSnapshot":{"question":"Điền các số thích hợp vào chỗ trống để hoàn thành quy đồng mẫu số:","mainQuestion":"","type":"DRAG_DROP","text":"Quy đồng mẫu số $\\frac{3}{4}$ và $\\frac{5}{8}$ (MSC là 8):\nGiữ nguyên phân số [5/8].\nBiến đổi: $\\frac{3}{4} = \\frac{3 \\times 2}{4 \\times 2} = $ [6/8].","blanks":["5/8","6/8"],"distractors":["3/8","8/8"]}},"q-1770211296984-18":{"isCorrect":false,"questionSnapshot":{"question":"Chọn số thích hợp để hoàn thành phép quy đồng:","mainQuestion":"","type":"DROPDOWN","text":"Quy đồng $\\frac{7}{9}$ và $\\frac{2}{3}$:\nTa chọn MSC là [1].\nTa có $\\frac{2}{3} = \\frac{2 \\times 3}{3 \\times 3} = $ [2].","blanks":[{"id":"blank-1","options":["9","27","3"]},{"id":"blank-2","options":["6/9","5/9","7/9"]}]}},"q-1770211296984-20":{"isCorrect":false,"questionSnapshot":{"question":"Quy đồng mẫu số ba phân số: $\\frac{1}{2}$ ; $\\frac{1}{3}$ ; $\\frac{1}{5}$. Mẫu số chung nhỏ nhất là: (MSC  nhỏ nhất là số chia hết cho 2,3 và 5)","mainQuestion":"","type":"MCQ","options":["A. 10","B. 15","C. 30","D. 60"],"correctAnswer":"C"}},"q-1770211296984-23":{"isCorrect":false,"questionSnapshot":{"question":"","mainQuestion":"Bạn Lan quy đồng mẫu số hai phân số $\\frac{5}{12}$ và $\\frac{3}{4}$. Hãy kiểm tra bài làm của Lan:","type":"TRUE_FALSE","items":[{"statement":"Lan chọn MSC là 12."},{"statement":"Lan biến đổi $\\frac{3}{4}$ thành $\\frac{9}{12}$."},{"statement":"Lan biến đổi $\\frac{5}{12}$ thành $\\frac{15}{12}$."}]}},"q-1770211296984-24":{"isCorrect":false,"questionSnapshot":{"question":"Điền từ thích hợp vào chỗ trống để hoàn thành câu kết luận:","mainQuestion":"","type":"DRAG_DROP","text":"Muốn quy đồng mẫu số hai phân số, ta có thể lấy tử số và mẫu số của phân số thứ nhất [nhân] với mẫu số của phân số thứ hai. Sau đó, lấy tử số và mẫu số của phân số thứ hai nhân với [mẫu số] của phân số thứ nhất.","blanks":["nhân","mẫu số"],"distractors":["chia","tử số"]}},"q-1770211296984-25":{"isCorrect":false,"questionSnapshot":{"question":"Mẹ có một cái bánh. Mẹ cho Anh $\\frac{1}{2}$ cái bánh và cho Em $\\frac{1}{4}$ cái bánh. Hỏi ai được nhiều bánh hơn?","mainQuestion":"","type":"MCQ","options":["A. Anh","B. Em","C. Hai người bằng nhau","D. Không so sánh được"],"correctAnswer":"A"}},"q-1770211296984-26":{"isCorrect":false,"que