"80":"t","81":"r","82":"ă","83":"m","84":" ","85":"n","86":"g","87":"ọ","88":"n","89":" ","90":"đ","91":"è","92":"n","93":" ","94":"m","95":"à","96":"u","97":" ","98":"t","99":"r","100":"ắ","101":"n","102":"g","103":" ","104":"n","105":"g","106":"à","107":" ","108":"x","109":"i","110":"n","111":"h","112":" ","113":"x","114":"ắ","115":"n","116":"."}]}},"q-manual-1771238140994":{"selectedAnswer":"B","isCorrect":true,"questionSnapshot":{"question":"Câu văn nào sử dụng biện pháp so sánh và nhân hóa mô tả đúng hình ảnh dưới đây?","mainQuestion":"","type":"IMAGE_QUESTION","options":["Trong vườn, những quả sầu riêng bắt đầu chín, hương thơm ngạt ngào lan xa trong không gian.","Những quả sầu riêng bụ bẫm, tinh nghịch đung đưa trên cành như những con nhím lớn, mình chi chít gai nhọn.","Những người nông dân đi thu hoạch sầu riêng chín, đem ra chợ bán.","Những múi sầu riêng chín vàng, vị ngọt ngào như mật ong và béo ngậy như bơ sữa."],"correctAnswer":"B"}},"q-manual-1771242464193":{"selectedAnswer":"C","isCorrect":true,"questionSnapshot":{"question":"Hình ảnh nào thích hợp để minh họa cho đoạn thơ dưới đây?\n“Tiếng khèn vang vách núi xa\nRừng mơ bung nở trắng nhoà mắt ai\nTựa cụm mây trắng mượt mà\nXuân về, cỏ biếc trải dài núi xanh.\"\n(Theo Trà My)","mainQuestion":"","type":"IMAGE_QUESTION","options":["A","B","C","D"],"correctAnswer":"C"}},"q-manual-1771242590463":{"selectedAnswer":"A","isCorrect":true,"questionSnapshot":{"question":"Câu văn nào sử dụng biện pháp so sánh mô tả đúng hình ảnh dưới đây?","mainQuestion":"","type":"IMAGE_QUESTION","options":["Nhìn từ trên cao xuống, những thửa ruộng xanh biếc như những bậc thang bắc lên trời.","Trên những ruộng lúa xanh biếc, mấy cô bác nông dân chăm chỉ đi làm cỏ, bón phân.","Ruộng bậc thang là nét đặc trưng của thiên nhiên vùng Tây Bắc.","Cánh đồng lúa như một thâm vàng trải rộng đến tận chân trời."],"correctAnswer":"A"}},"q-manual-1771242787730":{"selectedAnswer":"C","isCorrect":false,"questionSnapshot":{"question":"Sắp xếp các tiếng sau thành câu văn hoàn chỉnh.","mainQuestion":"","type":"IMAGE_QUESTION","options":["Chúng em tham dự kết nạp lễ Đội.","Chúng em tham dự lễ kết nạp Đội.","Chúng em tham dự Đội lễ kết nạp.","Chúng em kết nạp Đội tham dự."],"correctAnswer":"B"}},"q-manual-1771243453524":{"selectedAnswer":{"1":"hiền hoà","2":"bồng bềnh","3":"xanh mướt"},"isCorrect":true,"questionSnapshot":{"question":"Chọn từ ngữ thích hợp điền vào chỗ trống để hoàn thành đoạn văn miêu tả hình ảnh sau:","mainQuestion":"","type":"DROPDOWN","text":"Mùa này, con sông quê em [1] , soi bóng những đám mây trắng [2] trôi. Nhờ phù sa bồi đắp, cây cối hai bên bờ sông [3], tràn đầy sức sống.","blanks":[{"id":"1","options":["dữ dội","hiền hoà","cuồn cuộn"]},{"id":"2","options":["đen kịt","bồng bềnh","xám xịt"]},{"id":"3","options":["xơ xác","xanh mướt","héo úa"]}]}},"q-manual-1771250767538":{"selectedAnswer":"Thì","isCorrect":false,"questionSnapshot":{"question":"Giải câu đố sau:","mainQuestion":"","type":"RIDDLE","correctAnswer":"đua","riddleLines":["Giữ nguyên cùng nghĩa với “thi\"","Thêm huyền là nói điều gì cho vui."],"answerLabel":"Từ giữ nguyên là từ gì?"}},"q-manual-1771251011765":{"selectedAnswer":{"Tiếng chim":"vang ra không ngớt, vọng mãi lên trời cao xanh thẳm."," Những thân cây tràm":" vươn thẳng lên trời như những cây nến khổng lồ.","Rừng khô":"hiện lên uy nghi, tráng lệ trong ánh mặt trời vàng óng."},"isCorrect":true,"questionSnapshot":{"question":"","mainQuestion":"","type":"MATCHING","pairs":[{"left":"Tiếng chim","right":"vang ra không ngớt, vọng mãi lên trời cao xanh thẳm."},{"left":" Những thân cây tràm","right":" vươn thẳng lên trời như những cây nến khổng lồ."},{"left":"Rừng khô","right":"hiện lên uy nghi, tráng lệ trong ánh mặt trời vàng óng."}]}},"q-manual-1771251245761":{"isCorrect":false,"questionSnapshot":{"question":"Sắp xếp các chữ sau thành từ chỉ phẩm chất của con người:","mainQuestion":"","type":"WORD_SCRAMBLE","correctAnswer":"rộng lượng","letters":["N","L","G","G","Ư","R","Ộ","Ợ","N"],"correctWord":"rộng lượng"}},"q-manual-1771251785757":{"selectedAnswer":{"wrongWord":"Chải","correctWord":"Trải"},"isCorrect":true,"questionSnapshot":{"question":"<b>Điền từ thích hợp vào chỗ trống:</b>\n","mainQuestion":"","type":"ERROR_CORRECTION","correctAnswer":"trải"}}}');
INSERT OR REPLACE INTO results (student_name, class_name, quiz_id, quiz_title, score, correct_count, total_questions, submitted_at, answers) VALUES ('Lèo Thị Thuý Ngọc', '4A9', 'quiz-1771225368087', 'Ôn tập: Trạng Nguyên Tiếng Việt cấp tỉnh (Hội) - Lớp 4', 0, 17, 30, '2026-03-02T07:19:24.257Z', '{"q-1771225368087-5":{"selectedAnswer":"B","isCorrect":true,"questionSnapshot":{"question":"Đáp án nào dưới đây có từ viết sai chính tả?","mainQuestion":"","type":"MCQ","options":["xuất khẩu, xuất ăn","suôn sẻ, xương mù","rắn rỏi, chạm trổ","giặt giũ, giấu giếm"],"correctAnswer":"B"}},"q-1771225368087-7":{"selectedAnswer":"A","isCorrect":false,"questionSnapshot":{"question":"<b>Từ nào dưới đây có nghĩa giống với từ \"<i>chất phác</i>\"?</b>","mainQuestion":"","type":"MCQ","options":["gánh vác","chuyên cần","giản dị","chân chất"],"correctAnswer":"D"}},"q-1771225368087-12":{"selectedAnswer":{"1":"đã","3":"đang","5":"sẽ"},"isCorrect":true,"questionSnapshot":{"question":"Chọn từ thích hợp điền vào chỗ trống để hoàn thành các câu văn sau:","mainQuestion":"","type":"DRAG_DROP","text":"1. Tuần trước, lớp chúng em [đã] kêu gọi ủng hộ được nhiều quần áo, sách vở và gửi tặng cho các bạn học sinh vùng cao.\n2. Tôi [đang] ngồi đọc sách trong nhà thì bạn Hoa đến rủ đi học nhóm.\n3. Tôi [sẽ] cùng bố mẹ dọn vệ sinh khu phố vào cuối tuần này.","blanks":["đã","đang","sẽ"],"distractors":["lạ","nắng"]}},"q-1771225368087-13":{"selectedAnswer":"D","isCorrect":false,"questionSnapshot":{"question":"<b>Đáp án nào là chủ ngữ trong câu văn dưới đây? </b>\n<i>\"Hương thơm ngan ngát của hoa thiên lí bay xa trong đêm thâu.\"</i>","mainQuestion":"","type":"MCQ","options":["Hương thơm","Hương thơm ngan ngát","Hương thơm ngan ngát của hoa thiên lí","Hoa thiên lí"],"correctAnswer":"C"}},"q-1771225368087-17":{"selectedAnswer":"A","isCorrect":true,"questionSnapshot":{"question":"<b>Đọc đoạn thơ dưới đây và cho biết khung cảnh thiên nhiên vào mùa xuân ở Cà Mau được miêu tả như thế nào?</b>\n <i>\"Chân lội trong bùn tay vịn cành đước \nTôi gặp mùa xuân ở đất Mũi Cà Mau \nThuyền thấp thoáng trong màu xanh như chuốt\nNắng hồng phơi ong bay rợp trên đầu\" </i>","mainQuestion":"","type":"MCQ","options":["Vui tươi, tràn đầy sức sống","Kiêu sa, lộng lẫy","Hùng vĩ, hoành tráng","Hiện đại, phát triển"],"correctAnswer":"A"}},"q-manual-1771228559406":{"selectedAnswer":"A","isCorrect":false,"questionSnapshot":{"question":"<b>Câu nào dưới đây phân tách đúng thành phần chủ ngữ và vị ngữ? </b>","mainQuestion":"","type":"MCQ","options":["Hương thơm nồng nàn của những chùm hoa sữa/ làm đêm thu thêm mênh mang.","Bầu trời sau cơn mưa dường như/ trong xanh hơn, sạch như một tấm gương.","Tiếng cá quẫy/ làm xao động cả mặt sông lấp loáng ánh trăng vàng.","Ánh sáng/ ấm áp của những ngọn đèn đường chiếu sáng góc phố nhỏ."],"correctAnswer":"C"}},"q-manual-1771228763688":{"selectedAnswer":"A","isCorrect":false,"questionSnapshot":{"question":"<b>Thành ngữ, tục ngữ nào có thể thay thế bộ phận in đậm trong câu văn sau: </b>\n<i>\"Dù bị đặt trong tình huống khó xử, cô Hoa vẫn có cách giải quyết <b>thỏa đáng cả về lí lẽ lẫn tình cảm</b>.\"? </i>","mainQuestion":"","type":"MCQ","options":["Muôn hình vạn trạng","Một công đôi việc","Một lòng một dạ","Thấu tình đạt lý"],"correctAnswer":"D"}},"q-manual-1771228887685":{"selectedAnswer":"A","isCorrect":true,"questionSnapshot":{"question":"<b>Đọc đoạn văn sau và chọn đáp án đúng.\n</b>\n(1) Huế là vùng đất <b>nổi tiếng </b>với nhiều làn điệu truyền thống đặc sắc như nhã nhạc cung đình, hò mái nhì, mái đẩy..... (2) Người ta <b>thưởng thức</b> ca Huế trên dòng sông Hương thơ mộng. (3) Trong đêm trăng sáng, tiếng ca lúc thì <b>trữ tình</b>, sâu lắng, lúc lại <b>rộn rã</b>, vui tươi. (4) Dòng Hương Giang về đêm huyền ảo, nên thơ bởi ánh trăng vàng, ánh nến của những ngọn đèn hoa đăng và tiếng hát văng vẳng xa xa trên thuyền rồng.\n(Theo Trà My)\n","mainQuestion":"","type":"MCQ","options":["Đoạn văn trên có 1 câu giới thiệu.","Đoạn văn trên có 2 câu nêu hoạt động.","Đoạn văn trên có 1 câu sử dụng biện pháp so sánh.","Tất cả các từ in đậm trong đoạn văn trên là tính từ."],"correctAnswer":"A"}},"q-manual-1771229342455":{"selectedAnswer":"B","isCorrect":false,"questionSnapshot":{"question":"<b>Giải câu đố sau: \n</b>\"Tỉnh nào miền Trung nước ta \nTrường Sa quần đảo thiết tha tự hào \nTháp Bà ghi dấu thuở nào \nYến sào đặc sản mời chào ghé thăm?\" ","mainQuestion":"","type":"MCQ","options":["Đà Nẵng","Lâm Đồng","Khánh Hoà","Quảng Trị"],"correctAnswer":"C"}},"q-manual-1771230331506":{"selectedAnswer":"4","isCorrect":false,"questionSnapshot":{"question":"<b>Điền số thích hợp vào chỗ trống:</b>\n   (1) Trên đồng ruộng, trong nhà máy, trên lớp học hay trong bệnh viện, ở đâu, ta cũng gặp những trí thức đang lao động quên mình. (2) Các kĩ sư nông nghiệp nghiên cứu giống lúa mới, kĩ thuật trồng trọt, chăn nuôi mới. (3) Các kĩ sư cơ khícùng công nhân sản xuất máy móc, ô tô. (4) Các thầy giáo, cô giáo dạy ta thành người có ích cho xã hội. (5) Các bác sĩ chữa bệnh cho dân.\n<i>(Sưu tầm)</i>\n<i>Câu chủ đề của đoạn văn trên là câu số:\n</i>","mainQuestion":"","type":"SHORT_ANSWER","correctAnswer":1}},"q-manual-1771230537985":{"selectedAnswer":{"1":"chủ trì","3":"chủ quyền"},"isCorrect":false,"questionSnapshot":{"question":"<b>Chọn từ thích hợp trong ngoặc đơn điền vào chỗ trống:</b>","mainQuestion":"","type":"DRAG_DROP","text":"1. Từ [chủ động] có nghĩa là “tự mình quyết định hành động, không bị chi phối bởi\n2. Từ [chủ trì] có nghĩa là “điều hành và chịu trách nhiệm chính về công việc”.","blanks":["chủ động","chủ trì"],"distractors":["chủ quyền"]}},"q-manual-1771230686504":{"selectedAnswer":{"1":".","3":",","5":"!","7":"-"},"isCorrect":false,"questionSnapshot":{"question":"<b>Điền dấu câu thích hợp để hoàn thành câu chuyện sau:</b>","mainQuestion":"","type":"DRAG_DROP","text":"Một người nọ có một con lừa và một con ngựa. Một hôm, có việc đi xa [,] ông ta cưỡi ngựa, còn bao nhiêu đồ đạc nặng thì chất hết lưng lừa[.] Dọc đường, lừa mệt quá liền khẩn khoản với ngựa:\nNgựa ơi, bạn có thể mang đỡ giúp tôi chút đồ được không[?]Tôi kiệt sức rồi!\nNgựa kiêu ngạo đáp:\n- Thôi, việc ai người nấy lo, tôi không giúp bạn được.\nLúc sau, vì mang nặng quá, lừa gục xuống bên vệ đường. Người chủ thấy vậy chuyển hết đồ tử lưng lừa sang ngựa. Lúc này, ngựa mới than:\n- Ôi, tôi mới dại dột làm sao[!]Tôi không muốn giúp lừa nên bây giờ phải mang nặng gấp đôi.\n(Sưu tầm)\n","blanks":[",",".","?","!"],"distractors":["-"]}},"q-manual-1771231355290":{"selectedAnswer":"4","isCorrect":true,"questionSnapshot":{"question":"<b>Điền số thích hợp vào chỗ trống:</b>\nTừ các tiếng “<b>nguyện, toại, mãn, cầu</b>” có thể ghép được tất cả bao nhiêu từ?","mainQuestion":"","type":"SHORT_ANSWER","correctAnswer":4}},"q-manual-1771231432380":{"selectedAnswer":"Viết ","isCorrect":true,"questionSnapshot":{"question":"<b>Điền từ thích hợp vào chỗ trống:\n</b>Đôi bàn tay nhỏ\nViết dòng chữ xinh\nTrang giấy trắng tinh\nĐiểm mười thắm đỏ.\n<i>(Nguyễn Lâm Thắng)\n</i>Từ nào trong đoạn thơ trên là động từ?","mainQuestion":"","type":"SHORT_ANSWER","correctAnswer":"viết"}},"q-manual-1771231641694":{"selectedAnswer":"D","isCorrect":false,"questionSnapshot":{"question":"<b>Chọn từ thích hợp điền vào chỗ trống sau: Tiếng “<i>cảnh</i>” có thể ghép với tiếng … để tạo thành danh từ.</b>","mainQuestion":"","type":"MCQ","options":["phong","giác","tỉnh","cáo"],"correctAnswer":"A"}},"q-manual-1771231734884":{"selectedAnswer":{"hòa nhã":"Cô Lan là người rất dịu dàng, nói năng [...] với mọi người.","hòa quyện":"Vị chua, cay, ngọt [...] với nhau tạo nên hương vị độc đáo của món ăn.","hòa tấu":"Tiết mục [...] của các nghệ sĩ rất xuất sắc."},"isCorrect":true,"questionSnapshot":{"question":"","mainQuestion":"","type":"MATCHING","pairs":[{"left":"hòa nhã","right":"Cô Lan là người rất dịu dàng, nói năng [...] với mọi người."},{"left":"hòa quyện","right":"Vị chua, cay, ngọt [...] với nhau tạo nên hương vị độc đáo của món ăn."},{"left":"hòa tấu","right":"Tiết mục [...] của các nghệ sĩ rất xuất sắc."}]}},"q-manual-1771231816719":{"selectedAnswer":{"Cha truyền con nối":"Kế tục, nối tiếp nhau từ đời này sang đời khác","Bình an vô sự":"Yên ổn, không có trở ngại, khó khăn nào","Ơn sâu nghĩa nặng":"Ơn nghĩa sâu sắc, tình cảm đậm thắm","Nghĩ trước nghĩ sau\t":"Suy nghĩ đắn đo, kĩ lưỡng để cân nhắc việc gì đó"},"isCorrect":true,"questionSnapshot":{"question":"","mainQuestion":"","type":"MATCHING","pairs":[{"left":"Cha truyền con nối","right":"Kế tục, nối tiếp nhau từ đời này sang đời khác"},{"left":"Bình an vô sự","right":"Yên ổn, không có trở ngại, khó khăn nào"},{"left":"Ơn sâu nghĩa nặng","right":"Ơn nghĩa sâu sắc, tình cảm đậm thắm"},{"left":"Nghĩ trước nghĩ sau\t","right":"Suy nghĩ đắn đo, kĩ lưỡng để cân nhắc việc gì đó"}]}},"q-manual-1771231883511":{"selectedAnswer":{"item-1771231894552":"1","item-1771231923646":"1","item-1771231933431":"1","item-1771231982737":"2","item-1771232003998":"2","item-1771232005296":"2","item-1771231981099":"2","item-1771231955061":"1771231852702","item-1771232006386":"1771231852702"},"isCorrect":false,"questionSnapshot":{"question":"<b>Chọn đáp án sắp xếp các từ ngữ sau vào nhóm thích hợp.\n</b>","mainQuestion":"","type":"CATEGORIZATION","items":[{"id":"item-1771231894552","content":"lao công"},{"id":"item-1771231923646","content":"y tá"},{"id":"item-1771231933431","content":"thủ thư"},{"id":"item-1771231955061","content":"kiến thiết"},{"id":"item-1771231981099","content":"ghi chép"},{"id":"item-1771231982737","content":"lao động"},{"id":"item-1771232003998","content":"cần cù"},{"id":"item-1771232005296","content":"hăng say"},{"id":"item-1771232006386","content":"thanh khiết"}],"categories":[{"id":"1","name":"Danh từ"},{"id":"2","name":"Động từ"},{"id":"1771231852702","name":"Tính từ"}]}},"q-manual-1771232162321":{"selectedAnswer":{"1":"1","2":"1","1771232115852":"1","1771232126697":"2","1771232128538":"2","1771232129381":"2"},"isCorrect":true,"questionSnapshot":{"question":"<b>Chọn đáp án sắp xếp các 