,"80":"t","81":"r","82":"ă","83":"m","84":" ","85":"n","86":"g","87":"ọ","88":"n","89":" ","90":"đ","91":"è","92":"n","93":" ","94":"m","95":"à","96":"u","97":" ","98":"t","99":"r","100":"ắ","101":"n","102":"g","103":" ","104":"n","105":"g","106":"à","107":" ","108":"x","109":"i","110":"n","111":"h","112":" ","113":"x","114":"ắ","115":"n","116":"."}]}},"q-manual-1771238140994":{"selectedAnswer":"B","isCorrect":true,"questionSnapshot":{"question":"Câu văn nào sử dụng biện pháp so sánh và nhân hóa mô tả đúng hình ảnh dưới đây?","mainQuestion":"","type":"IMAGE_QUESTION","options":["Trong vườn, những quả sầu riêng bắt đầu chín, hương thơm ngạt ngào lan xa trong không gian.","Những quả sầu riêng bụ bẫm, tinh nghịch đung đưa trên cành như những con nhím lớn, mình chi chít gai nhọn.","Những người nông dân đi thu hoạch sầu riêng chín, đem ra chợ bán.","Những múi sầu riêng chín vàng, vị ngọt ngào như mật ong và béo ngậy như bơ sữa."],"correctAnswer":"B"}},"q-manual-1771242464193":{"selectedAnswer":"C","isCorrect":true,"questionSnapshot":{"question":"Hình ảnh nào thích hợp để minh họa cho đoạn thơ dưới đây?\n“Tiếng khèn vang vách núi xa\nRừng mơ bung nở trắng nhoà mắt ai\nTựa cụm mây trắng mượt mà\nXuân về, cỏ biếc trải dài núi xanh.\"\n(Theo Trà My)","mainQuestion":"","type":"IMAGE_QUESTION","options":["A","B","C","D"],"correctAnswer":"C"}},"q-manual-1771242590463":{"selectedAnswer":"A","isCorrect":true,"questionSnapshot":{"question":"Câu văn nào sử dụng biện pháp so sánh mô tả đúng hình ảnh dưới đây?","mainQuestion":"","type":"IMAGE_QUESTION","options":["Nhìn từ trên cao xuống, những thửa ruộng xanh biếc như những bậc thang bắc lên trời.","Trên những ruộng lúa xanh biếc, mấy cô bác nông dân chăm chỉ đi làm cỏ, bón phân.","Ruộng bậc thang là nét đặc trưng của thiên nhiên vùng Tây Bắc.","Cánh đồng lúa như một thâm vàng trải rộng đến tận chân trời."],"correctAnswer":"A"}},"q-manual-1771242787730":{"selectedAnswer":"B","isCorrect":true,"questionSnapshot":{"question":"Sắp xếp các tiếng sau thành câu văn hoàn chỉnh.","mainQuestion":"","type":"IMAGE_QUESTION","options":["Chúng em tham dự kết nạp lễ Đội.","Chúng em tham dự lễ kết nạp Đội.","Chúng em tham dự Đội lễ kết nạp.","Chúng em kết nạp Đội tham dự."],"correctAnswer":"B"}},"q-manual-1771243453524":{"selectedAnswer":{"1":"hiền hoà","2":"bồng bềnh","3":"xanh mướt"},"isCorrect":true,"questionSnapshot":{"question":"Chọn từ ngữ thích hợp điền vào chỗ trống để hoàn thành đoạn văn miêu tả hình ảnh sau:","mainQuestion":"","type":"DROPDOWN","text":"Mùa này, con sông quê em [1] , soi bóng những đám mây trắng [2] trôi. Nhờ phù sa bồi đắp, cây cối hai bên bờ sông [3], tràn đầy sức sống.","blanks":[{"id":"1","options":["dữ dội","hiền hoà","cuồn cuộn"]},{"id":"2","options":["đen kịt","bồng bềnh","xám xịt"]},{"id":"3","options":["xơ xác","xanh mướt","héo úa"]}]}},"q-manual-1771250767538":{"selectedAnswer":"Đùa","isCorrect":false,"questionSnapshot":{"question":"Giải câu đố sau:","mainQuestion":"","type":"RIDDLE","correctAnswer":"đua","riddleLines":["Giữ nguyên cùng nghĩa với “thi\"","Thêm huyền là nói điều gì cho vui."],"answerLabel":"Từ giữ nguyên là từ gì?"}},"q-manual-1771251011765":{"selectedAnswer":{"Tiếng chim":"vang ra không ngớt, vọng mãi lên trời cao xanh thẳm."," Những thân cây tràm":" vươn thẳng lên trời như những cây nến khổng lồ.","Rừng khô":"hiện lên uy nghi, tráng lệ trong ánh mặt trời vàng óng."},"isCorrect":true,"questionSnapshot":{"question":"","mainQuestion":"","type":"MATCHING","pairs":[{"left":"Tiếng chim","right":"vang ra không ngớt, vọng mãi lên trời cao xanh thẳm."},{"left":" Những thân cây tràm","right":" vươn thẳng lên trời như những cây nến khổng lồ."},{"left":"Rừng khô","right":"hiện lên uy nghi, tráng lệ trong ánh mặt trời vàng óng."}]}},"q-manual-1771251245761":{"isCorrect":false,"questionSnapshot":{"question":"Sắp xếp các chữ sau thành từ chỉ phẩm chất của con người:","mainQuestion":"","type":"WORD_SCRAMBLE","correctAnswer":"rộng lượng","letters":["N","L","G","G","Ư","R","